import { useState, useEffect } from "react"
import { getGifs } from '../helpers/getGifs'

export const useFetchGifs = (category) => {

	const [state, setState] = useState({
		data: [],
		loading: true
	})

	useEffect( () => {

		const getGifImages = async () => {
			
			const gifs = await getGifs(category)

			setState({
				data: gifs,
				loading: false
			})
		}
		getGifImages()

	}, [category])

	return state

}

